#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int C[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &C[i]);
        }
        int freq[1001] = {0};
        for (int i = 0; i < N; i++) {
            freq[C[i]]++;
        }
        long long ans = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int score = 0;
            for (int i = 1; i <= 1000; i++) {
                int a = 0, b = freq[i];
                for (int j = 0; j < N; j++) {
                    if ((mask & (1 << j)) && C[j] == i) {
                        a++;
                        b--;
                    }
                }
                if (a > b) {
                    score += a - b;
                } else {
                    score -= abs(a - b);
                }
            }
            if (score > 0) {
                ans++;
            }
        }
        printf("%lld\n", ans % MOD);
    }
    return 0;
}

