import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] C = new int[N];
            for (int i = 0; i < N; i++) {
                C[i] = sc.nextInt();
            }
            int[] freq = new int[1001];
            for (int i = 0; i < N; i++) {
                freq[C[i]]++;
            }
            long ans = 0;
            for (int mask = 0; mask < (1 << N); mask++) {
                int score = 0;
                for (int i = 1; i <= 1000; i++) {
                    int a = 0, b = freq[i];
                    for (int j = 0; j < N; j++) {
                        if ((mask & (1 << j)) != 0 && C[j] == i) {
                            a++;
                            b--;
                        }
                    }
                    if (a > b) {
                        score += a - b;
                    } else {
                        score -= Math.abs(a - b);
                    }
                }
                if (score > 0) {
                    ans++;
                }
            }
            System.out.println(ans % 1000000007);
        }
    }
}

